import{_ as i,c as a,a as e,o as n}from"./app-CEcM0piI.js";const l={};function d(p,s){return n(),a("div",null,s[0]||(s[0]=[e(`<h2 id="局部作用域" tabindex="-1"><a class="header-anchor" href="#局部作用域"><span>局部作用域</span></a></h2><p>使用作用域符{}包裹的区域就是一个局部作用域,不在作用域范围内无法使用作用域里面的变量(var声明的变量除外) let和const声明的变量会产生块作用域,var不会产生块作用域</p><p>在js中允许函数嵌套定义</p><h2 id="全局作用域" tabindex="-1"><a class="header-anchor" href="#全局作用域"><span>全局作用域</span></a></h2><p>&lt;script&gt;标签和js文件的【最外层】就是所谓的全局作用域，在此声明的变量在函数内部也可以被访问。 全局作用域中声明的变量，任何其它作用域都可以被访问</p><ol><li>为window对象动态添加的属性默认也是全局的，不推荐！</li><li>函数中未使用任何关键字声明的变量为全局变量，不推荐！！！</li><li>尽可能少的声明全局变量，防止全局变量被污染</li></ol><h1 id="垃圾回收机制" tabindex="-1"><a class="header-anchor" href="#垃圾回收机制"><span>垃圾回收机制</span></a></h1><p>垃圾回收机制(Garbage Collection）简称GC JS中内存的分配和回收都是自动完成的，内存在不使用的时候会被垃圾回收器自动回收</p><p><strong>内存的生命周期</strong> JS环境中分配的内存，一般有如下生命周期：</p><ol><li>内存分配：当我们声明变量、函数、对象的时候，系统会自动为他们分配内存</li><li>内存使用：即读写内存，也就是使用变量、函数等</li><li>内存回收：使用完毕，由垃圾回收器自动回收不再使用的内存</li></ol><p>全局变量一般不会回收(关闭页面回收) 一般情况下局部变量的值，不用了，会被自动回收掉</p><p>内存泄漏：程序中分配的内存由于某种原因程序未释放或无法释放叫做内存泄漏</p><p>堆栈空间分配区别：</p><ol><li>栈（操作系统）：由操作系统自动分配释放函数的参数值、局部变量等，基本数据类型放到栈里面。</li><li>堆（操作系统）：一般由程序员分配释放，若程序员不释放，由垃圾回收机制回收。复杂数据类型放到堆里面。</li></ol><h2 id="垃圾回收算法" tabindex="-1"><a class="header-anchor" href="#垃圾回收算法"><span>垃圾回收算法</span></a></h2><p>两种常见的浏览器垃圾回收算法：<strong>引用计数法</strong>和<strong>标记清除法</strong></p><h3 id="引用计数法" tabindex="-1"><a class="header-anchor" href="#引用计数法"><span>引用计数法</span></a></h3><p>IE采用的引用计数算法，定义“内存不再使用”，就是看一个对象是否有指向它的引用，没有引用了就回收对象</p><p><strong>算法：</strong></p><ol><li>跟踪记录被引用的次数</li><li>如果被引用了一次，那么就记录次数1，多次引用会累加++</li><li>如果减少一个引用就减1</li><li>如果引用次数是0，则释放内存</li></ol><p>但它却存在一个致命的问题：嵌套引用月（循环引用） 如果两个对象相互引用，尽管他们已不再使用，垃圾回收器不会进行回收，导致内存泄露。</p><h3 id="标记清除法" tabindex="-1"><a class="header-anchor" href="#标记清除法"><span>标记清除法</span></a></h3><p>现代的浏览器已经不再使用引用计数算法了。 现代浏览器通用的大多是基于标记清除算法的某些改进算法，总体思想都是一致的。</p><p>核心：</p><ol><li>标记清除算法将“不再使用的对象”定义为“无法达到的对象”</li><li>就是从根部（在JS中就是全局对象）出发定时扫描内存中的对象。凡是能从根部到达的对象，都是还需要使用的。</li><li>那些无法由根部出发触及到的对象被标记为不再使用，稍后进行回收。</li></ol><h1 id="闭包" tabindex="-1"><a class="header-anchor" href="#闭包"><span>闭包</span></a></h1><p>一个函数对周围状态的引用捆绑在一起，内层函数中访问到其外层函数的作用域</p><p>闭包=内层函数+外层函数的变量</p><p>简单的示例</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function outer(){</span></span>
<span class="line"><span>	const a=1</span></span>
<span class="line"><span>	function f() {</span></span>
<span class="line"><span>		console.log(a)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	f()</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>outer()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>函数之间嵌套是不会产生闭包的 里层函数用到了外层函数的变量对外层函数产生了捆绑就是闭包</p><p>闭包的常见用法是让其他外部函数使用另一个外部函数的内部变量</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function outer(){</span></span>
<span class="line"><span>	let a=100</span></span>
<span class="line"><span>	function fn() {</span></span>
<span class="line"><span>		console.log(a)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	return fn</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>const fun = outer()</span></span>
<span class="line"><span>fun()//相当于调用fn</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="作用" tabindex="-1"><a class="header-anchor" href="#作用"><span>作用</span></a></h4><p>可以避免让一个变量被外部修改\\</p><p>例如做一个计数的函数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let count =1</span></span>
<span class="line"><span>function fn(){</span></span>
<span class="line"><span>	count++</span></span>
<span class="line"><span>	console.log(函数被调用\${count}次)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>fn()    //2</span></span>
<span class="line"><span>fn()    //3</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样写count就是一个全局变量容易被修改</p><p>使用闭包</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function fn(){</span></span>
<span class="line"><span>	let count =1</span></span>
<span class="line"><span>	function Fun(){</span></span>
<span class="line"><span>		count++</span></span>
<span class="line"><span>		console.log（函数被调用\${count}次)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	return fun</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>const result = fn()</span></span>
<span class="line"><span>result()//2</span></span>
<span class="line"><span>result() // 3</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样count就是一个函数内部的变量避免了被外部修改,同时在外部调用闭包时也会对count继续累加而不是只在当前代码块内被访问 由于result变量使用了闭包函数,因此这个函数以及它内部的数据都不会被回收</p><h1 id="变量提升" tabindex="-1"><a class="header-anchor" href="#变量提升"><span>变量提升</span></a></h1><p>js程序在执行之前会把所有var声明的变量提升到当前作用域的最前面.只提升声明，不提升赋值</p><p>所以var定义的变量可以放在使用之后</p><h1 id="函数" tabindex="-1"><a class="header-anchor" href="#函数"><span>函数</span></a></h1><h2 id="函数提升" tabindex="-1"><a class="header-anchor" href="#函数提升"><span>函数提升</span></a></h2><p>函数提升与变量提升比较类似，是指函数在声明之前即可被调用，</p><p>js执行前会把所有函数声明提升到当前作用域的最前面.只提升函数声明，不提升函数调用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>调用函数</span></span>
<span class="line"><span>foo()</span></span>
<span class="line"><span>//声明函数</span></span>
<span class="line"><span>function foo(){</span></span>
<span class="line"><span>	console.log()&#39;声明之前即被调用..&#39;)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但函数表达式不存在提升的现象,即使是赋值给var变量</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//不存在提升现象</span></span>
<span class="line"><span>bar()// 错误</span></span>
<span class="line"><span>var bar = function () {</span></span>
<span class="line"><span>	console.log()&#39;函数表达式不存在提升现象...&quot;)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="函数参数" tabindex="-1"><a class="header-anchor" href="#函数参数"><span>函数参数</span></a></h2><h3 id="动态参数" tabindex="-1"><a class="header-anchor" href="#动态参数"><span>动态参数</span></a></h3><p>arugments arguments动态参数只存在于函数里面,是一个伪数组</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function getSum(){</span></span>
<span class="line"><span>	console.log(arugments)    //[1,2,3]</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>getSum(1,2,3)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>只有使用function定义的函数才有arguments,箭头函数没有</p><h3 id="剩余参数" tabindex="-1"><a class="header-anchor" href="#剩余参数"><span>剩余参数</span></a></h3><p>...arg 动态形参</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function getSum(...arg){</span></span>
<span class="line"><span>	for(e : arg){</span></span>
<span class="line"><span>		console.log(e)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>getSum(1,2,3)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>剩余参数是一个真数组 剩余参数必须声明在形参列表最后</p><h3 id="展开运算符" tabindex="-1"><a class="header-anchor" href="#展开运算符"><span>展开运算符</span></a></h3><p>展开运算符也是... 它用来展开一个数组</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const arr = [1, 5, 3, 8, 2]</span></span>
<span class="line"><span>console.log(...arr)    // 1 5 3 8 2</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>不会修改原数组</p><h4 id="合并数组" tabindex="-1"><a class="header-anchor" href="#合并数组"><span>合并数组</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const arr1=[1,2,3]</span></span>
<span class="line"><span>const arr2=[4,5,6]</span></span>
<span class="line"><span>const arr=[...arr1,...arr2]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="箭头函数" tabindex="-1"><a class="header-anchor" href="#箭头函数"><span>箭头函数</span></a></h3><p>引入箭头函数的目的是更简短的函数写法并且不绑定this，箭头函数的语法比函数表达式更简洁 在箭头函数中没有this指针</p><p>箭头函数中没有arguments,但是又剩余参数</p><p>箭头函数用来取代(简化)匿名函数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const fn=(x)=&gt;{</span></span>
<span class="line"><span>	sonsole.log(x)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>fn(1)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>只有一行代码的时候可以省略大括号</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const fn = x =&gt; console.log(x)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果只有的一行代码是要返回值的也可以省略返回值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const fn = x =&gt; x+1</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>只有一行且返回值被小括号和大括号括起来的时候可以之间返回字面量</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const fn =(uname) =&gt;({name: uname})</span></span>
<span class="line"><span>console.log(fn(&#39;刘德华&#39;))    //name: &#39;刘德华&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>箭头函数不会创建自己的this，它只会从自己的作用域链的上一层沿用this。</strong> 也就是箭头函数中的this是它父亲的this</p><h1 id="解构赋值" tabindex="-1"><a class="header-anchor" href="#解构赋值"><span>解构赋值</span></a></h1><h2 id="数组的解构" tabindex="-1"><a class="header-anchor" href="#数组的解构"><span>数组的解构</span></a></h2><p>数组解构是将数组的单元值快速批量赋值给一系列变量的简洁语法</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const [a,b,c] = [1,2,3]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>交换元素值的用法:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>consta=1</span></span>
<span class="line"><span>constb=2;</span></span>
<span class="line"><span>[b, a] = [a, b]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但以数组开头的写法时要注意,尽量在 前面加分号隔开,不然js在解析时会解析错误</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const a=1</span></span>
<span class="line"><span>const b=2</span></span>
<span class="line"><span>[b, a].map()</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//会解析为</span></span>
<span class="line"><span>//const b=2[b, a].map()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>所以js在立即执行函数和数组结构的这两种情况下必须加分号</p><p><strong>变量多,单元值少</strong> 如果赋值的变量超过了数组元素的个数,那么超过部分就是undefined</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const[a,b,c,d]=[1,2,3]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>d就是undefined</p><p>为了避免undefined传递可以给数组结构的变量设置默认值,这样赋不到值得变量也会有默认值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const[a=0,b=0,c=0,d=0]=[1,2,3]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>变量少,单元值多</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const[a,b]=[1,2,3]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>a=1,b=2</p><p>也可以使用剩余参数解决单元值比变量少的情况</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const [a,b,...c] = [1,2,3,4]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>这样c就是一个数组[3,4]</p><h4 id="多维数组解构" tabindex="-1"><a class="header-anchor" href="#多维数组解构"><span>多维数组解构</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const[a,b,c] =[1,2, [3, 4]]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>c=[3,4]</p><p>可以多维解构</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const[a,b,[c,d]] =[1,2, [3, 4]]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="对象解构" tabindex="-1"><a class="header-anchor" href="#对象解构"><span>对象解构</span></a></h2><p>将对象中的变量赋值给外部变量</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const {uname,age}={uname,&#39;pink老师&#39;,age:1888}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在解构时变量名要与对象的属性名一致,且前面不能有和对象属性名同名的const常量</p><p>要只解构想要的数据只写对应的属性名即可</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const msg={</span></span>
<span class="line"><span>	&quot;code&quot;:200,</span></span>
<span class="line"><span>	&quot;msg&quot;:&quot;获取消息列表成功,</span></span>
<span class="line"><span>	&quot;data&quot;:[{...}.{...}]</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>const {data}=msg</span></span>
<span class="line"><span></span></span>
<span class="line"><span>function render({data}){}</span></span>
<span class="line"><span>render(msg)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="对象解构的变量名改名" tabindex="-1"><a class="header-anchor" href="#对象解构的变量名改名"><span>对象解构的变量名改名</span></a></h5><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const {uname:username,age}={uname:&#39;pink老师&#39;,age:18}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="foreach" tabindex="-1"><a class="header-anchor" href="#foreach"><span>forEach</span></a></h1><p>forEach(）方法用于调用数组的每个元素，并将元素传递给回调函数 主要使用场景：遍历数组的每个元素</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>被遍历的数组.forEach(function(当前数组元素,当前元素索引号){</span></span>
<span class="line"><span>	//函数体</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>forEach可以更改数组中的值</p>`,115)]))}const r=i(l,[["render",d]]),c=JSON.parse('{"path":"/front/js/4/","title":"4 ES6","lang":"zh-CN","frontmatter":{"title":"4 ES6","createTime":"2025/06/15 13:34:10","permalink":"/front/js/4/"},"readingTime":{"minutes":7.95,"words":2384},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/JavaScript/4 ES6.md","headers":[]}');export{r as comp,c as data};
